<template>
  <div class="h5-container">
    <!-- 进度指示器 -->
    <div class="progress-indicator">
      <div
        v-for="(page, index) in pages"
        :key="index"
        class="progress-dot"
        :class="{ active: currentIndex === index }"
        @click="goToPage(index)"
        :title="page.title"
      ></div>
    </div>

    <!-- 页面内容 -->
    <div class="page-wrapper">
      <transition :name="transitionName" mode="out-in">
        <router-view :key="$route.path" />
      </transition>
    </div>

    <!-- 导航按钮 -->
    <div class="nav-buttons" v-if="!isFirstPage && !isLastPage">
      <el-button
        v-if="!isFirstPage"
        class="nav-btn prev-btn"
        icon="el-icon-arrow-up"
        circle
        @click="prevPage"
      ></el-button>
      <el-button
        v-if="!isLastPage"
        class="nav-btn next-btn"
        icon="el-icon-arrow-down"
        circle
        @click="nextPage"
      ></el-button>
    </div>
  </div>
</template>

<script>
export default {
  name: 'H5Container',
  data() {
    return {
      pages: [
        { path: '/background', title: '非遗基础认知' },
        { path: '/data-visualization', title: '核心数据可视化' },
        { path: '/reality-gap', title: '现实反差探究' },
        { path: '/inheritance-path', title: '传承路径分析' },
        { path: '/breakout-plans', title: '四大破圈方案' },
        { path: '/interaction', title: '互动参与' },
        { path: '/ending', title: '结尾升华' }
      ],
      currentIndex: 0,
      transitionName: 'slide-down'
    }
  },
  computed: {
    isFirstPage() {
      return this.currentIndex === 0
    },
    isLastPage() {
      return this.currentIndex === this.pages.length - 1
    }
  },
  watch: {
    '$route.path': {
      handler(newPath) {
        const index = this.pages.findIndex(p => p.path === newPath)
        if (index !== -1) {
          this.currentIndex = index
        }
      },
      immediate: true
    }
  },
  methods: {
    goToPage(index) {
      if (index !== this.currentIndex) {
        this.transitionName = index > this.currentIndex ? 'slide-down' : 'slide-up'
        this.$router.push(this.pages[index].path)
      }
    },
    nextPage() {
      if (!this.isLastPage) {
        this.transitionName = 'slide-down'
        this.$router.push(this.pages[this.currentIndex + 1].path)
      }
    },
    prevPage() {
      if (!this.isFirstPage) {
        this.transitionName = 'slide-up'
        this.$router.push(this.pages[this.currentIndex - 1].path)
      }
    },
  }
}
</script>

<style scoped>
.page-wrapper {
  position: relative;
  overflow: hidden;
}

/* 导航按钮 */
.nav-buttons {
  position: fixed;
  right: 20px;
  bottom: 30px;
  z-index: 999;
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.nav-btn {
  width: 50px;
  height: 50px;
  background: linear-gradient(135deg, #8B4513, #D2691E);
  border: none;
  color: #fff;
  font-size: 20px;
  box-shadow: 0 4px 12px rgba(139, 69, 19, 0.3);
}

.nav-btn:hover {
  transform: scale(1.1);
  box-shadow: 0 6px 16px rgba(139, 69, 19, 0.4);
}

/* 页面切换动画 */
.slide-down-enter-active,
.slide-down-leave-active,
.slide-up-enter-active,
.slide-up-leave-active {
  transition: all 0.5s ease;
}

.slide-down-enter {
  transform: translateY(100%);
  opacity: 0;
}

.slide-down-leave-to {
  transform: translateY(-100%);
  opacity: 0;
}

.slide-up-enter {
  transform: translateY(-100%);
  opacity: 0;
}

.slide-up-leave-to {
  transform: translateY(100%);
  opacity: 0;
}

@media (max-width: 750px) {
  .nav-buttons {
    right: 15px;
    bottom: 20px;
  }
  
  .nav-btn {
    width: 45px;
    height: 45px;
  }
}
</style>





















